import{_ as a,o as r,c,a3 as s}from"./chunks/framework.DxStgKjp.js";const u=JSON.parse('{"title":"Architecture","description":"","frontmatter":{},"headers":[],"relativePath":"zh/clice/design/architecture.md","filePath":"zh/clice/design/architecture.md"}'),o={name:"zh/clice/design/architecture.md"};function i(l,e,n,t,d,p){return r(),c("div",null,[...e[0]||(e[0]=[s('<h1 id="architecture" tabindex="-1">Architecture <a class="header-anchor" href="#architecture" aria-label="Permalink to &quot;Architecture&quot;">​</a></h1><p>clice 采用<strong>多进程</strong>架构：一个主服务器（master）协调多个工作进程（worker）。主进程处理 LSP 请求、管理状态并分发编译任务；工作进程执行 CPU 密集型工作（解析、索引），运行在独立进程中并有内存限制。</p><p>异步运行时由 <a href="https://github.com/clice-io/kotatsu" target="_blank" rel="noreferrer">kotatsu</a>（<code>kota</code>）提供，它基于 libuv 封装了 C++20 协程。clice 不直接调用 libuv。</p><h2 id="源码模块" tabindex="-1">源码模块 <a class="header-anchor" href="#源码模块" aria-label="Permalink to &quot;源码模块&quot;">​</a></h2><h3 id="src-command" tabindex="-1"><code>src/command/</code> <a class="header-anchor" href="#src-command" aria-label="Permalink to &quot;`src/command/`&quot;">​</a></h3><p>CLI 解析、编译数据库加载与工具链检测。实现子命令式接口（<code>clice server</code>、<code>clice query</code> 等）。</p><h3 id="src-compile" tabindex="-1"><code>src/compile/</code> <a class="header-anchor" href="#src-compile" aria-label="Permalink to &quot;`src/compile/`&quot;">​</a></h3><p>编译单元抽象。对 Clang 的 AST 和预处理器状态进行封装：</p><ul><li><code>CompilationUnitRef</code> — 统一访问源码位置、预处理指令、文件内容</li><li><code>DiagnosticID</code> — 诊断分类（deprecated、unused 等）</li><li>预处理指令追踪（includes、embeds、模块声明）</li></ul><h3 id="src-feature" tabindex="-1"><code>src/feature/</code> <a class="header-anchor" href="#src-feature" aria-label="Permalink to &quot;`src/feature/`&quot;">​</a></h3><p>LSP 功能实现，每个功能消费一个 <code>CompilationUnitRef</code>：</p><ul><li>代码补全、悬停信息、签名帮助</li><li>语义高亮、内嵌提示、文档符号</li><li>文档链接、折叠范围、格式化、诊断</li></ul><h3 id="src-index" tabindex="-1"><code>src/index/</code> <a class="header-anchor" href="#src-index" aria-label="Permalink to &quot;`src/index/`&quot;">​</a></h3><p>符号索引，用于跨翻译单元的查询：</p><ul><li><code>TUIndex</code> — 单翻译单元的符号数据</li><li><code>ProjectIndex</code> — 全局跨 TU 符号索引</li><li><code>MergedIndex</code> — 按文件分片，合并多个头文件上下文</li><li>包含关系图追踪</li></ul><p>使用 FlatBuffers 序列化，高效磁盘存储。</p><h3 id="src-semantic" tabindex="-1"><code>src/semantic/</code> <a class="header-anchor" href="#src-semantic" aria-label="Permalink to &quot;`src/semantic/`&quot;">​</a></h3><p>超越 Clang 原生能力的语义分析：</p><ul><li><code>SemanticVisitor</code> — AST 遍历，记录符号出现和关系</li><li><code>TemplateResolver</code> — 伪实例化，解析依赖名称</li><li><code>find_target</code> — 将节点解析到其声明目标</li><li>符号种类/修饰符分类</li></ul><h3 id="src-syntax" tabindex="-1"><code>src/syntax/</code> <a class="header-anchor" href="#src-syntax" aria-label="Permalink to &quot;`src/syntax/`&quot;">​</a></h3><p>轻量级语法层处理（不需要完整 AST）：</p><ul><li><code>Lexer</code>（<code>lexer.h</code>）与指令扫描（<code>scan.h</code>，封装 Clang 的 <code>DependencyDirectivesScanner</code>）— token 级别的工具</li><li><code>DependencyGraph</code> — 模块/包含依赖追踪</li><li>包含路径补全、模块导入补全</li></ul><h3 id="src-server" tabindex="-1"><code>src/server/</code> <a class="header-anchor" href="#src-server" aria-label="Permalink to &quot;`src/server/`&quot;">​</a></h3><p>服务器核心，分为多个子模块：</p><h4 id="src-server-service" tabindex="-1"><code>src/server/service/</code> <a class="header-anchor" href="#src-server-service" aria-label="Permalink to &quot;`src/server/service/`&quot;">​</a></h4><ul><li><code>MasterServer</code> — 顶层 LSP 服务器，将请求路由到 session/worker</li><li><code>LSPClient</code> — LSP 协议处理，能力注册</li><li><code>Session</code> — 每文件状态（活跃上下文、待处理请求）</li></ul><h4 id="src-server-compiler" tabindex="-1"><code>src/server/compiler/</code> <a class="header-anchor" href="#src-server-compiler" aria-label="Permalink to &quot;`src/server/compiler/`&quot;">​</a></h4><ul><li><code>Compiler</code> — 编译调度（PCH、PCM、索引构建）</li><li><code>CompileGraph</code> — 基于兴趣计数的模块 DAG，支持取消</li><li><code>Indexer</code> — 后台索引、查询解析</li></ul><h4 id="src-server-worker" tabindex="-1"><code>src/server/worker/</code> <a class="header-anchor" href="#src-server-worker" aria-label="Permalink to &quot;`src/server/worker/`&quot;">​</a></h4><ul><li><code>StatefulWorker</code> — 在内存中持有 AST，服务查询（hover、semantic tokens 等）</li><li><code>StatelessWorker</code> — 无状态任务（PCH/PCM 构建、补全、签名帮助）</li><li><code>WorkerPool</code> — 进程生命周期管理</li></ul><h4 id="src-server-workspace" tabindex="-1"><code>src/server/workspace/</code> <a class="header-anchor" href="#src-server-workspace" aria-label="Permalink to &quot;`src/server/workspace/`&quot;">​</a></h4><ul><li><code>Workspace</code> — 项目状态、配置、依赖图</li><li><code>Config</code> — TOML/JSON 配置加载与校验</li></ul><h3 id="src-support" tabindex="-1"><code>src/support/</code> <a class="header-anchor" href="#src-support" aria-label="Permalink to &quot;`src/support/`&quot;">​</a></h3><p>工具库：日志、文件系统辅助、JSON 序列化、字符串操作。</p><h2 id="进程模型" tabindex="-1">进程模型 <a class="header-anchor" href="#进程模型" aria-label="Permalink to &quot;进程模型&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>┌─────────────────────────────────────────────────┐</span></span>\n<span class="line"><span>│                    主进程 (Master)                 │</span></span>\n<span class="line"><span>│  事件循环 (kota) + LSP I/O + 状态管理             │</span></span>\n<span class="line"><span>└────────────┬──────────────────┬─────────────────┘</span></span>\n<span class="line"><span>             │ bincode IPC      │ bincode IPC</span></span>\n<span class="line"><span>     ┌───────▼───────┐   ┌─────▼──────────┐</span></span>\n<span class="line"><span>     │ 有状态工作进程   │   │ 无状态工作进程   │</span></span>\n<span class="line"><span>     │ (Stateful ×2) │   │ (Stateless ×N/2)│</span></span>\n<span class="line"><span>     │ 持有 AST，     │   │ 构建 PCH/PCM，  │</span></span>\n<span class="line"><span>     │ 服务查询       │   │ 补全、签名帮助   │</span></span>\n<span class="line"><span>     └───────────────┘   └─────────────────┘</span></span></code></pre></div><p>工作进程通过 stdin/stdout 使用 bincode 序列化与主进程通信。每个工作进程运行在独立进程中，可配置内存限制（默认 4 GB）。</p>',37)])])}const m=a(o,[["render",i]]);export{u as __pageData,m as default};
